import React, { useEffect, useState } from 'react'
import * as _Util from '../store/Util';
import { getSectionByGtoken, updObserveChanges } from '../actions/common'
import { useSelector } from 'react-redux'
import { selectObserveChanges } from '../store/qvamarketsSlice';




const LoginComponent = (props) => {  
  const [initialize, setInitialize] = useState(false);
  const observeChanges =  useSelector(selectObserveChanges);

  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      _Util.initGapi(()=>renderBtn());

    }
  })



  /*********************************************************************************************************************************************/  
  /**************************************   renderBtn load auht function and render google singin button ****************************************/
  /*********************************************************************************************************************************************/
  


  const renderBtn = () => {
    let _gapi = window.gapi;
    _gapi.load('auth2', function() {
      setTimeout(()=>{
        _gapi.signin2.render('google-signin-button', {
          width: 232,
          height: 40,
          longtitle: true,
          hidden:true,
          onsuccess: onSuccess,
          onfailure: onFail,
        });
        setTimeout(()=>{
          let cu = _gapi.auth2.getAuthInstance();
          let currentUser = cu && cu.currentUser.get()
          let authResponse = currentUser && currentUser.getAuthResponse();
          if(authResponse.id_token){
            var id_token = authResponse.id_token;
            var access_token = authResponse.access_token;
            let Qry = {
              params:{
                id_token:id_token,
                access_token:access_token
              },
              query:"getGoogleUserbyToken"
            };
            if(!(_Util.getStore('userProfile') && _Util.getStore('userProfile').email)){
              getSectionByGtoken(Qry)
            }
          }
        },350)
      },350)
    });
  }

  const onFail = (e) => {
    console.log("onFail",e)
  }


  const onSuccess = (e) => {
    let _gapi = window.gapi;
    let cu = _gapi.auth2.getAuthInstance();
    let currentUser = cu && cu.currentUser.get()
    let authResponse = currentUser && currentUser.getAuthResponse();
    
    var id_token = authResponse.id_token;
    var access_token = authResponse.access_token;
    let Qry = {
      params:{
        id_token:id_token,
        access_token:access_token
      },
      query:"getGoogleUserbyToken"
    };
    if(!(_Util.getStore('userProfile') && _Util.getStore('userProfile').email)){
      getSectionByGtoken(Qry)
    }
  }

  var _thumbnailJson = _Util.getStore()['thumbnailJsonBlob'] && _Util.getStore()['thumbnailJsonBlob']["qvaMarket_logo2.png"];
  let _blobrequested =  _thumbnailJson && _thumbnailJson['requested'];
  let _blob = _blobrequested? _thumbnailJson['blob'] : null;



  return (
    <>
    {initialize?
      <div id="g_signin2_bx" >
        <div class="login_message" >
          <img src={_blob} alt="qvaMarket"/>
          <p>
            {_Util.translatetext(22)}
          </p>
          <div class="_dsplFlx">
            <div class="flexSpace"></div>
            <div id="google-signin-button" data-theme="dark"  ></div>
          </div>
        </div>
      </div>
    :null}
    </>
  )
}


export default LoginComponent

